[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode [ a schema1:Role ;
                    schema1:contributor <https://example.org/NyMWPlRtQizAFE> ;
                    schema1:roleName "data steward" ] ;
            sh:resultMessage "a Role must be filled by either a Person or an organization" ;
            sh:resultPath schema1:contributor ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:OrConstraintComponent ;
            sh:sourceShape [ sh:description "https://cross-domain-interoperability-framework.github.io/cdifbook/metadata/schemaorgimplementation.html" ;
                    sh:message "a Role must be filled by either a Person or an organization" ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:class schema1:Person ] [ sh:class schema1:Organization ] ) ;
                    sh:path schema1:contributor ] ;
            sh:value <https://example.org/NyMWPlRtQizAFE> ] .

